body.script:
//
    const bareServerData = {
        "servers": [
            "https://rhw.one",
            "https://phantomnetwork.cloud",
            "https://artclass.site",
            "https://shuttleproxy.com"
        ]
    };

    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        bareServerData.servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Bypassing protocol error using an In-Memory Fetch Interception Hook
    async function loadProxyService() {
        if (!('serviceWorker' in navigator)) return;

        try {
            const cdnWorkerUrl = 'https://jsdelivr.net';
            console.log('Downloading remote proxy source code structure...');

            const response = await fetch(cdnWorkerUrl);
            const proxyScriptText = await response.text();

            // Intercept standard Service Worker registration
            const nativeRegister = navigator.serviceWorker.register.bind(navigator.serviceWorker);

            navigator.serviceWorker.register = async function(url, options) {
                console.log("Hooked active system registration. Overriding request targets.");

                // Bind the execution layout directly to your domain space /uv/ fallback
                // This ensures the browser reads a clean HTTP/S protocol path target string
                const targetPath = options.scope ? options.scope + 'sw.js' : '/uv/service/sw.js';

                // Inject client-side execution parameters straight into window properties
                window.__uvWorkerRawCode = proxyScriptText;

                return nativeRegister(targetPath, { 
                    scope: options.scope || '/uv/service/' 
                });
            };

            console.log("SVG Interceptor routing ready.");
        } catch (err) {
            console.error("Initialization error:", err);
        }
    }

    window.addEventListener('load', () => {
        populateDropdown();
        loadProxyService();
    });
//
